import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o,c,e as d}from"./app-be253e4c.js";const a={},l=d(`<h1 id="more命令" tabindex="-1"><a class="header-anchor" href="#more命令" aria-hidden="true">#</a> more命令</h1><p><code>more</code>命令类似<code>less</code>，以分页的形式浏览文件内容，在<code>more</code>命令退出后会在<code>shell</code>上留下操作的内容，在分页浏览时使用<code>h</code>键输出说明文件。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">more</span> <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token punctuation">[</span>file<span class="token punctuation">]</span>
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li><code>-d</code>: 提示使用者，在画面下方显示<code>[Press space to continue, &#39;q&#39; to quit.]</code>，如果使用者按错键，则会显示<code>[Press &#39;h&#39; for instructions.]</code>而不是滴声。</li><li><code>-f</code>: 计算行数时，以实际上的行数，而非自动换行过后的行数，某些单行字数太长的会被扩展为两行或两行以上。</li><li><code>-l</code>: 取消遇见特殊字元<code>^L</code>送纸字元时会暂停的功能。</li><li><code>-c</code>: 不进行滚动而是从顶部绘制每个屏幕，清除每行显示的其余部分，跟<code>-p</code>相似，不同的是先显示内容再清除其他输出。</li><li><code>-p</code>: 不以滚动的方式显示每一页，而是先清除输出后再显示内容。</li><li><code>-s</code>: 当遇到有连续两行以上的空白行，就代换为一行的空白行。</li><li><code>-u</code>: 不显示下划线，根据环境变数<code>TERM</code>指定的<code>terminal</code>而有所不同。</li><li><code>-&lt;num&gt;</code>: 指定每屏的行数。</li><li><code>+&lt;num&gt;</code>: 从第<code>num</code>行开始显示。</li><li><code>+/&lt;str&gt;</code>: 在每个文档显示前搜寻字串<code>str</code>，然后从该字串之后开始显示。</li><li><code>-V</code>: 显示版本信息。</li></ul><h2 id="常用操作" tabindex="-1"><a class="header-anchor" href="#常用操作" aria-hidden="true">#</a> 常用操作</h2><ul><li><code>h or ?</code>: 帮助菜单，显示命令的摘要。</li><li><code>SPACE</code>: 显示接下来的<code>k</code>行文本，默认为当前屏幕尺寸。</li><li><code>Enter</code>: 向下<code>n</code>行，需要定义，默认为<code>1</code>行。</li><li><code>Ctrl+F</code>: 向下滚动一屏。</li><li><code>Ctrl+B</code>: 返回上一屏。</li><li><code>=</code>: 输出当前行的行号。</li><li><code>:f</code>: 输出文件名和当前行的行号。</li><li><code>V</code>: 调用<code>vi</code>编辑器。</li><li><code>! &lt;cmd&gt;</code>: 调用<code>Shell</code>，并执行命令。</li><li><code>q</code>: 退出<code>more</code>命令。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>分页显示<code>/var/log/ufw.log</code>文件内容。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">more</span> /var/log/ufw.log
</code></pre></div><p>从第<code>20</code>行开始显示<code>/var/log/ufw.log</code>文件内容。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">more</span> +20 /var/log/ufw.log
</code></pre></div><p>以<code>1</code>行分页显示<code>/var/log/ufw.log</code>文件内容。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">more</span> <span class="token parameter variable">-1</span> /var/log/ufw.log
</code></pre></div>`,15),s=[l];function i(n,t){return o(),c("div",null,s)}const p=e(a,[["render",i],["__file","more.html.vue"]]);export{p as default};
